/**
 * Research service — reads Titanite JSON exports for the Next.js frontend.
 *
 * Architecture rules (from AGENTS.md):
 * - All API/data calls go through src/lib/services/. Never raw fetch in components.
 * - NEXT_PUBLIC_USE_MOCK_DATA=true uses mock data; false reads from public/research-data/.
 * - This service is server-side only (reads filesystem JSON, not a remote API).
 *
 * Data source: public/research-data/*.json — generated by `titanite export`
 * To refresh data: cd research/titanite-app && titanite export
 */

import type {
  ResearchedCompany,
  ResearchCatalyst,
  CompaniesPayload,
  CatalystsPayload,
  HoldingsPayload,
} from '@/types/research';

const USE_MOCK = process.env.NEXT_PUBLIC_USE_MOCK_DATA === 'true';

// ---------------------------------------------------------------------------
// Data fetchers — server-side only (no 'use client' in callers)
// ---------------------------------------------------------------------------

async function fetchResearchJson<T>(filename: string): Promise<T> {
  // Server-side: read directly from the filesystem (public/ dir)
  // This works during next build, SSR, and ISR without needing a running server.
  if (typeof window === 'undefined') {
    const { readFileSync } = await import('fs');
    const { join } = await import('path');
    const filePath = join(process.cwd(), 'public', 'research-data', filename);
    try {
      const raw = readFileSync(filePath, 'utf-8');
      return JSON.parse(raw) as T;
    } catch {
      throw new Error(
        `Could not read ${filePath}. ` +
        `Run 'titanite export' to generate research-data/ JSON files.`
      );
    }
  }

  // Client-side fallback (shouldn't be reached — this service is server-only)
  const res = await fetch(`/research-data/${filename}`, {
    next: { revalidate: 300 },
  });
  if (!res.ok) {
    throw new Error(`Failed to fetch ${filename}: ${res.status}`);
  }
  return res.json() as Promise<T>;
}

