// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/** Fetch all researched companies. Sorted by score descending. */
export async function getResearchedCompanies(): Promise<ResearchedCompany[]> {
  if (USE_MOCK) {
    return MOCK_COMPANIES.sort((a, b) => b.score - a.score);
  }

  const payload = await fetchResearchJson<CompaniesPayload>('companies.json');
  return payload.companies.sort((a, b) => b.score - a.score);
}

/** Fetch active catalysts only, sorted by ticker. */
export async function getActiveCatalysts(): Promise<ResearchCatalyst[]> {
  if (USE_MOCK) {
    return MOCK_CATALYSTS;
  }

  const payload = await fetchResearchJson<CatalystsPayload>('catalysts.json');
  return payload.catalysts.filter((c) => c.status === 'active');
}

/** Fetch current Titanite holdings (subset of companies currently held). */
export async function getResearchHoldings(): Promise<ResearchedCompany[]> {
  if (USE_MOCK) {
    return MOCK_COMPANIES.filter((c) => ['PENG', 'ACCON', 'AAOI', 'TLN'].includes(c.ticker));
  }

  const payload = await fetchResearchJson<HoldingsPayload>('holdings.json');
  return payload.holdings;
}

/**
 * Build a lookup map from ticker → ResearchedCompany.
 * Used to enrich T212 holdings with Titanite scores.
 */
export function buildResearchLookup(
  companies: ResearchedCompany[]
): Map<string, ResearchedCompany> {
  return new Map(companies.map((c) => [c.ticker.toUpperCase(), c]));
}

/** Get the export timestamp from the companies payload. */
export async function getResearchExportedAt(): Promise<string | null> {
  if (USE_MOCK) return new Date().toISOString();
  try {
    const payload = await fetchResearchJson<CompaniesPayload>('companies.json');
    return payload.exportedAt;
  } catch {
    return null;
  }
}
